import React, { useEffect, useMemo } from 'react';
import { Card, Stack, Box, Divider, Text, Heading, Icon, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionIcon(condition: string): string {
  const normalized = (condition ?? '').trim().toLowerCase();
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '🌨️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('cloud') || normalized.includes('overcast') || normalized.includes('fog') || normalized.includes('mist')) return '☁️';
  if (normalized.includes('wind') || normalized.includes('breezy')) return '💨';
  if (normalized.includes('clear') || normalized.includes('sun') || normalized.includes('fair')) return '☀️';
  return '🌤️';
}

function formatTemperature(value: number, unit: string): string {
  return `${value}°${unit}`;
}

export default function GeneratedComponent(props: Props) {
  const city = props.city ?? '—';
  const temperature = props.temperature ?? 0;
  const condition = props.condition ?? 'Unknown';
  const humidity = props.humidity ?? 0;
  const windSpeed = props.windSpeed ?? 0;
  const unit = props.unit ?? 'C';
  const forecast = props.forecast ?? [];

  const conditionIcon = useMemo(() => getConditionIcon(condition), [condition]);

  useEffect(() => {
    const handler = (_event: Event) => undefined;
    return () => undefined;
  }, []);

  return (
    <>
      <MotionKeyframes />
      <Card
        role="region"
        aria-label={`Weather in ${city}`}
        shadow="md"
        radius="xl"
        border={true}
        padding="var(--ggui-spacing-6, 24px)"
      >
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="horizontal" justify="between" align="start" gap="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Heading level={3}>{city}</Heading>
              <Text
                variant="bodyLarge"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {condition}
              </Text>
            </Stack>

            <Box
              padding="var(--ggui-spacing-2, 8px)"
              background="var(--ggui-color-primary-50, #f0f9ff)"
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
              style={{
                transition: 'background-color 200ms ease-in-out, color 200ms ease-in-out',
              }}
            >
              <Icon name={conditionIcon} size={40} color="var(--ggui-color-primary-600, #0284c7)" aria-hidden="true" />
            </Box>
          </Stack>

          <Text
            variant="body"
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {formatTemperature(temperature, unit)}
          </Text>

          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap={true}>
            <Box
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              style={{ flex: '1 1 180px' }}
            >
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="label" weight="semibold">
                  {humidity}%
                </Text>
              </Stack>
            </Box>

            <Box
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              style={{ flex: '1 1 180px' }}
            >
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text variant="label" weight="semibold">
                  {windSpeed} km/h
                </Text>
              </Stack>
            </Box>
          </Stack>

          <Divider margin="var(--ggui-spacing-2, 8px)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box
            role="list"
            aria-label="5-day forecast"
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between" wrap={true}>
              {forecast.map((item, index) => {
                const day = item.day ?? '—';
                const icon = item.icon ?? '🌤️';
                const high = item.high ?? 0;
                const low = item.low ?? 0;

                return (
                  <Box
                    key={`${day}-${index}`}
                    role="listitem"
                    padding="var(--ggui-spacing-2, 8px)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      flex: '1 1 92px',
                      minWidth: '92px',
                      textAlign: 'center',
                      transition: 'background-color 200ms ease-in-out, transform 200ms ease-in-out',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day}
                      </Text>
                      <Text is="span" aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', lineHeight: 1 }}>
                        {icon}
                      </Text>
                      <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                        {formatTemperature(high, unit)}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {formatTemperature(low, unit)}
                      </Text>
                    </Stack>
                  </Box>
                );
              })}
            </Stack>
          </Box>
        </Stack>
      </Card>
    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Card,
  Checkbox,
  Container,
  Divider,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  RadioGroup,
  Stack,
  Text,
  TextArea,
  Button,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
}

type SurveyPayload = {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
};

export default function GeneratedComponent(props: Props) {
  const featureOptions = props.featureOptions ?? [
    'Dashboard Analytics',
    'Team Collaboration',
    'API Integration',
    'Custom Workflows',
    'Mobile App',
    'AI Assistance',
  ];
  const satisfactionLabels = props.satisfactionLabels ?? [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ];

  const copy = useMemo(
    () => ({
      title: 'Survey',
      progressLabel: 'Step',
      ofLabel: 'of',
      next: 'Next',
      back: 'Back',
      submit: 'Submit Survey',
      reviewTitle: 'Review your answers',
      reviewDescription: 'Please confirm everything before submitting.',
      success: 'Survey submitted successfully.',
      error: 'Something went wrong while submitting the survey.',
      nameLabel: 'Name',
      emailLabel: 'Email',
      commentsLabel: 'Comments',
      commentsPlaceholder: 'Share any open-ended feedback...',
      commentsHelper: 'Optional. You can add up to 500 characters.',
      namePlaceholder: 'Enter your name',
      emailPlaceholder: 'you@example.com',
      step1Title: 'Tell us about yourself',
      step1Description: 'We need a name and a valid email address to continue.',
      step2Title: 'How satisfied are you?',
      step2Description: 'Choose the label that best matches your experience.',
      step3Title: 'Which features interest you?',
      step3Description: 'Select any features you want to learn more about.',
      step4Title: 'Anything else to share?',
      step4Description: 'This is optional, but detailed feedback helps us improve.',
      nameRequired: 'Name is required.',
      emailRequired: 'Email is required.',
      emailInvalid: 'Enter a valid email address.',
      satisfactionRequired: 'Please select a satisfaction rating.',
      reviewFeaturesNone: 'None selected',
      reviewCommentsNone: 'No comments',
    }),
    []
  );

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [nameTouched, setNameTouched] = useState<boolean>(false);
  const [emailTouched, setEmailTouched] = useState<boolean>(false);
  const [satisfactionTouched, setSatisfactionTouched] = useState<boolean>(false);
  const [commentsTouched, setCommentsTouched] = useState<boolean>(false);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [submitSuccess, setSubmitSuccess] = useState<string | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);

  useEffect(() => {
    setSubmitError(null);
    setSubmitSuccess(null);
  }, [currentStep]);

  useEffect(() => {
    if (!submitSuccess) return;
    const timer = setTimeout(() => setSubmitSuccess(null), 3500);
    return () => clearTimeout(timer);
  }, [submitSuccess]);

  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();

  const nameError = nameTouched && trimmedName.length === 0 ? copy.nameRequired : '';
  const emailError = emailTouched
    ? trimmedEmail.length === 0
      ? copy.emailRequired
      : !emailRegex.test(trimmedEmail)
        ? copy.emailInvalid
        : ''
    : '';

  const satisfactionError = satisfactionTouched && !satisfaction ? copy.satisfactionRequired : '';

  const isStep1Valid = trimmedName.length > 0 && trimmedEmail.length > 0 && emailRegex.test(trimmedEmail);
  const isStep2Valid = satisfaction.length > 0;
  const isStep3Valid = true;
  const isStep4Valid = comments.length <= 500;

  const currentStepValid =
    currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : currentStep === 3 ? isStep3Valid : isStep4Valid;

  const selectedSatisfactionIndex = useMemo(() => {
    const parsed = Number(satisfaction);
    return Number.isFinite(parsed) ? parsed - 1 : -1;
  }, [satisfaction]);

  const selectedSatisfactionLabel = selectedSatisfactionIndex >= 0 ? satisfactionLabels[selectedSatisfactionIndex] ?? '' : '';

  const payload: SurveyPayload = {
    name: trimmedName,
    email: trimmedEmail,
    satisfaction: selectedSatisfactionIndex >= 0 ? selectedSatisfactionIndex + 1 : 0,
    features: selectedFeatures,
    comments: comments.trim(),
  };

  const handleNext = () => {
    if (isSubmitting) return;

    if (currentStep === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!isStep1Valid) return;
    }

    if (currentStep === 2) {
      setSatisfactionTouched(true);
      if (!isStep2Valid) return;
    }

    setCurrentStep((step) => Math.min(4, step + 1));
  };

  const handleBack = () => {
    if (isSubmitting) return;
    setCurrentStep((step) => Math.max(1, step - 1));
  };

  const handleSubmit = async () => {
    setNameTouched(true);
    setEmailTouched(true);
    setSatisfactionTouched(true);
    setCommentsTouched(true);

    if (!isStep1Valid || !isStep2Valid || !isStep4Valid) {
      if (!isStep1Valid) setCurrentStep(1);
      else if (!isStep2Valid) setCurrentStep(2);
      else if (!isStep4Valid) setCurrentStep(4);
      return;
    }

    try {
      setIsSubmitting(true);
      setSubmitError(null);
      await Promise.resolve((props as unknown as { onSubmit?: (data: SurveyPayload) => void }).onSubmit?.(payload));
      setSubmitSuccess(copy.success);
    } catch {
      setSubmitError(copy.error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const stepIndicator = `${copy.progressLabel} ${currentStep} ${copy.ofLabel} 4`;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg" border>
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={3}>{copy.title}</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite" is="div">
              {stepIndicator}
            </Text>
            <Progress value={currentStep} max={4} size="md" variant="default" showLabel={false} />
          </Stack>

          <Divider margin="var(--ggui-spacing-2, 8px)" />

          <Stack gap="var(--ggui-spacing-4, 16px)">
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={4}>{copy.step1Title}</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {copy.step1Description}
                  </Text>
                </Stack>
                <Input
                  label={copy.nameLabel}
                  value={name}
                  onChange={(value) => {
                    setName(value);
                    if (!nameTouched) setNameTouched(true);
                    setSubmitError(null);
                  }}
                  placeholder={copy.namePlaceholder}
                  required
                  error={nameError}
                  disabled={isSubmitting}
                />
                <Input
                  label={copy.emailLabel}
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    if (!emailTouched) setEmailTouched(true);
                    setSubmitError(null);
                  }}
                  placeholder={copy.emailPlaceholder}
                  required
                  error={emailError}
                  disabled={isSubmitting}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={4}>{copy.step2Title}</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {copy.step2Description}
                  </Text>
                </Stack>
                <RadioGroup
                  label="Satisfaction rating"
                  value={satisfaction}
                  onChange={(value) => {
                    setSatisfaction(value);
                    if (!satisfactionTouched) setSatisfactionTouched(true);
                    setSubmitError(null);
                  }}
                  options={satisfactionLabels.map((label, index) => ({
                    value: String(index + 1),
                    label,
                  }))}
                  direction="vertical"
                  error={satisfactionError}
                  disabled={isSubmitting}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={4}>{copy.step3Title}</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {copy.step3Description}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {featureOptions.map((feature) => {
                    const checked = selectedFeatures.includes(feature);
                    return (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={checked}
                        onChange={(nextChecked) => {
                          setSelectedFeatures((current) =>
                            nextChecked ? Array.from(new Set([...current, feature])) : current.filter((item) => item !== feature)
                          );
                          setSubmitError(null);
                        }}
                        disabled={isSubmitting}
                      />
                    );
                  })}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={4}>{copy.reviewTitle}</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {copy.reviewDescription}
                  </Text>
                </Stack>

                <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="md" border>
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {copy.nameLabel}
                      </Text>
                      <Text variant="bodySmall">{trimmedName || '—'}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {copy.emailLabel}
                      </Text>
                      <Text variant="bodySmall">{trimmedEmail || '—'}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Satisfaction
                      </Text>
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap align="center">
                        <Text variant="bodySmall">
                          {selectedSatisfactionIndex >= 0 ? selectedSatisfactionIndex + 1 : '—'}
                        </Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {selectedSatisfactionLabel || '—'}
                        </Text>
                      </Stack>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Features
                      </Text>
                      <Text variant="bodySmall">
                        {selectedFeatures.length > 0 ? selectedFeatures.join(', ') : copy.reviewFeaturesNone}
                      </Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {copy.commentsLabel}
                      </Text>
                      <Text variant="bodySmall">{comments.trim().length > 0 ? comments : copy.reviewCommentsNone}</Text>
                    </Stack>
                  </Stack>
                </Card>

                <TextArea
                  label={copy.commentsLabel}
                  value={comments}
                  onChange={(value) => {
                    setComments(value);
                    if (!commentsTouched) setCommentsTouched(true);
                    setSubmitError(null);
                  }}
                  placeholder={copy.commentsPlaceholder}
                  helperText={copy.commentsHelper}
                  rows={5}
                  maxLength={500}
                  showCount
                  disabled={isSubmitting}
                />
              </Stack>
            )}

            {submitSuccess && (
              <Alert variant="success" title="Success">
                {submitSuccess}
              </Alert>
            )}
            {submitError && (
              <Alert variant="error" title="Submission failed">
                {submitError}
              </Alert>
            )}
          </Stack>

          <Divider margin="var(--ggui-spacing-2, 8px)" />

          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between" wrap align="center">
            <Button variant="ghost" size="md" onClick={handleBack} disabled={isSubmitting || currentStep === 1} aria-label="Go back">
              {copy.back}
            </Button>

            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap justify="end">
              {currentStep < 4 ? (
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleNext}
                  disabled={isSubmitting || !currentStepValid}
                  aria-label="Go to next step"
                >
                  {copy.next}
                </Button>
              ) : (
                <Button
                  variant="primary"
                  size="md"
                  onClick={handleSubmit}
                  loading={isSubmitting}
                  disabled={isSubmitting || !isStep1Valid || !isStep2Valid || !isStep4Valid}
                  aria-label={copy.submit}
                >
                  {copy.submit}
                </Button>
              )}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Badge, Box, Card, Container, Divider, Heading, Input, MotionKeyframes, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

type ElementData = {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
};

type CategoryStyle = {
  background: string;
  color: string;
  border: string;
  badgeVariant: 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' | 'secondary';
};

const categoryStyles: Record<string, CategoryStyle> = {
  'alkali-metal': {
    background: 'var(--ggui-color-warning-100, #fef3c7)',
    color: 'var(--ggui-color-warning-700, #b45309)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
    badgeVariant: 'warning',
  },
  'alkaline-earth-metal': {
    background: 'var(--ggui-color-primary-100, #e0f2fe)',
    color: 'var(--ggui-color-primary-700, #0369a1)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
    badgeVariant: 'primary',
  },
  'transition-metal': {
    background: 'var(--ggui-color-info-100, #cffafe)',
    color: 'var(--ggui-color-info-700, #0e7490)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
    badgeVariant: 'info',
  },
  'post-transition-metal': {
    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    border: 'var(--ggui-color-outlineVariant, #e4e4e7)',
    badgeVariant: 'secondary',
  },
  metalloid: {
    background: 'var(--ggui-color-success-100, #dcfce7)',
    color: 'var(--ggui-color-success-700, #15803d)',
    border: 'var(--ggui-color-success-200, #bbf7d0)',
    badgeVariant: 'success',
  },
  nonmetal: {
    background: 'var(--ggui-color-primary-50, #f0f9ff)',
    color: 'var(--ggui-color-primary-700, #0369a1)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
    badgeVariant: 'primary',
  },
  halogen: {
    background: 'var(--ggui-color-warning-100, #fef3c7)',
    color: 'var(--ggui-color-warning-700, #b45309)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
    badgeVariant: 'warning',
  },
  'noble-gas': {
    background: 'var(--ggui-color-info-100, #cffafe)',
    color: 'var(--ggui-color-info-700, #0e7490)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
    badgeVariant: 'info',
  },
  lanthanide: {
    background: 'var(--ggui-color-primary-50, #f0f9ff)',
    color: 'var(--ggui-color-primary-800, #075985)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
    badgeVariant: 'primary',
  },
  actinide: {
    background: 'var(--ggui-color-error-100, #fee2e2)',
    color: 'var(--ggui-color-error-700, #b91c1c)',
    border: 'var(--ggui-color-error-200, #fecaca)',
    badgeVariant: 'error',
  },
  unknown: {
    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    border: 'var(--ggui-color-outlineVariant, #e4e4e7)',
    badgeVariant: 'default',
  },
};

function normalizeCategory(category?: string): string {
  return (category ?? 'unknown').trim().toLowerCase();
}

function getCategoryStyle(category?: string): CategoryStyle {
  return categoryStyles[normalizeCategory(category)] ?? categoryStyles.unknown;
}

function formatAtomicWeight(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '—';
  return value.toFixed(3).replace(/\.?0+$/, '');
}

function formatCellLabel(element: ElementData): string {
  const name = element.name ?? 'Unknown';
  const symbol = element.symbol ?? '?';
  const number = element.atomicNumber ?? '-';
  const category = element.category ?? 'unknown';
  const weight = typeof element.atomicWeight === 'number' ? formatAtomicWeight(element.atomicWeight) : '—';
  return `${name}, symbol ${symbol}, atomic number ${number}, category ${category}, atomic weight ${weight}`;
}

function formatElementTitle(element: ElementData): string {
  const name = element.name ?? 'Unknown';
  const symbol = element.symbol ?? '?';
  return `${name} (${symbol})`;
}

function compareCategories(a: string, b: string): number {
  return a.localeCompare(b);
}

