import React, { useEffect, useMemo, useState } from 'react';
import { Alert, Badge, Box, Button, Card, Container, Divider, Heading, Icon, Input, MotionKeyframes, Stack, Table, Tabs, Text } from '@ggui-ai/design/primitives';

interface Props {
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void | Promise<void>;
}

type SpecRow = { key: string; value: string };
type ReviewRow = { author: string; rating: number; text: string; date: string };

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function toText(value: unknown): string {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (value instanceof Date) return value.toLocaleString();
  return '';
}

function formatPrice(price: number, currency: string): string {
  try {
    return new Intl.NumberFormat(undefined, {
      style: 'currency',
      currency,
      currencyDisplay: 'symbol',
      maximumFractionDigits: 2,
    }).format(price);
  } catch {
    return `${(currency ?? 'USD').toUpperCase()} ${price.toFixed(2)}`;
  }
}

function formatDate(value: string): string {
  if (!value) return '';
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? value : parsed.toLocaleDateString();
}

function parseSpecifications(items: unknown[] | undefined): SpecRow[] {
  return (items ?? []).map((item, index) => {
    if (isRecord(item)) {
      return {
        key: toText(item.key ?? item.name ?? item.label) || `Specification ${index + 1}`,
        value: toText(item.value ?? item.val ?? item.content) || '—',
      };
    }
    if (Array.isArray(item) && item.length >= 2) {
      return {
        key: toText(item[0]) || `Specification ${index + 1}`,
        value: toText(item[1]) || '—',
      };
    }
    return { key: `Specification ${index + 1}`, value: toText(item) || '—' };
  });
}

function parseReviews(items: unknown[] | undefined): ReviewRow[] {
  return (items ?? []).map((item, index) => {
    if (isRecord(item)) {
      const ratingRaw = Number(item.rating ?? 0);
      const rating = Number.isFinite(ratingRaw) ? Math.max(0, Math.min(5, Math.round(ratingRaw))) : 0;
      return {
        author: toText(item.author ?? item.name) || `Reviewer ${index + 1}`,
        rating,
        text: toText(item.text ?? item.content ?? item.review) || 'No review text provided.',
        date: toText(item.date ?? item.timestamp ?? item.createdAt) || '',
      };
    }
    return {
      author: `Reviewer ${index + 1}`,
      rating: 0,
      text: toText(item) || 'No review text provided.',
      date: '',
    };
  });
}

function Stars({ rating }: { rating: number }) {
  const rounded = Math.max(0, Math.min(5, Math.round(rating)));
  return (
    <Stack direction="horizontal" gap={4} align="center" aria-label={`Rating: ${rounded} out of 5`}>
      {Array.from({ length: 5 }).map((_, index) => (
        <Icon
          key={index}
          name="star"
          size={16}
          color={
            index < rounded
              ? 'var(--ggui-color-warning, var(--ggui-color-warning-500, var(--ggui-color-warning-500, var(--ggui-color-warning-500, #d97706))))'
              : 'var(--ggui-color-outline, var(--ggui-color-outlineVariant, #d4d4d8))'
          }
          aria-hidden="true"
        />
      ))}
    </Stack>
  );
}

function SpecTable({ specifications }: { specifications: SpecRow[] }) {
  if (!specifications.length) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications provided.</Text>;
  }

  return (
    <Table
      caption="Product specifications"
      bordered
      compact
      hoverable={false}
      striped={false}
      columns={[
        {
          key: 'key',
          header: 'Specification',
          render: (value) => <Text variant="bodySmall" weight="medium">{String(value ?? '')}</Text>,
        },
        {
          key: 'value',
          header: 'Value',
          render: (value) => <Text variant="bodySmall">{String(value ?? '')}</Text>,
        },
      ]}
      data={specifications}
    />
  );
}

function ReviewList({ reviews }: { reviews: ReviewRow[] }) {
  if (!reviews.length) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>;
  }

  return (
    <Stack gap={12}>
      {reviews.map((review, index) => (
        <Card key={`${review.author}-${index}`} padding={16} shadow="none" border>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center" gap={12} wrap>
              <Stack gap={4}>
                <Text variant="label" weight="semibold">{review.author}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {review.date ? formatDate(review.date) : 'Date unavailable'}
                </Text>
              </Stack>
              <Stack direction="horizontal" align="center" gap={8} wrap>
                <Stars rating={review.rating} />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.rating}/5</Text>
              </Stack>
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">{review.text}</Text>
          </Stack>
        </Card>
      ))}
    </Stack>
  );
}

function QuantitySelector(props: {
  stock: number;
  quantity: number;
  onDecrement: () => void;
  onIncrement: () => void;
  onChange: (value: string) => void;
  disabled: boolean;
  submitting: boolean;
  error: string;
}) {
  const maxQty = Math.max(1, props.stock);

  return (
    <Box style={{ minWidth: '180px', flex: '1 1 180px' }}>
      <Input
        label="Quantity"
        type="number"
        value={String(props.quantity)}
        onChange={props.onChange}
        disabled={props.submitting || props.disabled}
        helperText={props.disabled ? 'Stock is unavailable.' : `Minimum 1, maximum ${maxQty}.`}
        error={props.error}
        aria-label="Quantity input"
      />
      <Stack direction="horizontal" gap={8} align="center" style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
        <Button
          variant="outline"
          size="sm"
          onClick={props.onDecrement}
          disabled={props.submitting || props.disabled || props.quantity <= 1}
          aria-label="Decrease quantity"
        >
          <Icon name="minus" size={16} />
        </Button>
        <Button
          variant="outline"
          size="sm"
          onClick={props.onIncrement}
          disabled={props.submitting || props.disabled || props.quantity >= maxQty}
          aria-label="Increase quantity"
        >
          <Icon name="plus" size={16} />
        </Button>
      </Stack>
    </Box>
  );
}

function AddToCartArea(props: {
  productId: string;
  stock: number;
  quantity: number;
  setQuantity: React.Dispatch<React.SetStateAction<number>>;
  onAddToCart?: (payload: { productId: string; quantity: number }) => void | Promise<void>;
}) {
  const [submittedOnce, setSubmittedOnce] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ kind: 'success' | 'error'; message: string } | null>(null);

  const outOfStock = props.stock <= 0;

  const quantityError =
    submittedOnce && props.quantity < 1
      ? 'Quantity must be at least 1.'
      : submittedOnce && !outOfStock && props.quantity > props.stock
        ? `Quantity cannot exceed available stock (${props.stock}).`
        : '';

  const submit = async () => {
    setSubmittedOnce(true);
    setFeedback(null);

    if (!props.productId) {
      setFeedback({ kind: 'error', message: 'Product ID is missing.' });
      return;
    }
    if (outOfStock) {
      setFeedback({ kind: 'error', message: 'This product is out of stock.' });
      return;
    }
    if (props.quantity < 1) {
      setFeedback({ kind: 'error', message: 'Quantity must be at least 1.' });
      return;
    }
    if (props.quantity > props.stock) {
      setFeedback({ kind: 'error', message: `Quantity cannot exceed available stock (${props.stock}).` });
      return;
    }

    setIsSubmitting(true);
    try {
      await Promise.resolve(props.onAddToCart?.({ productId: props.productId, quantity: props.quantity }));
      setFeedback({ kind: 'success', message: `${props.quantity} item${props.quantity === 1 ? '' : 's'} added to cart.` });
    } catch {
      setFeedback({ kind: 'error', message: 'Unable to add item to cart. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Box
      padding={16}
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
    >
      <Stack gap={16}>
        <Heading level={4}>Add to Cart</Heading>
        <Stack direction="horizontal" gap={12} align="end" wrap>
          <QuantitySelector
            stock={props.stock}
            quantity={props.quantity}
            onDecrement={() => props.setQuantity((c) => Math.max(1, c - 1))}
            onIncrement={() => props.setQuantity((c) => Math.min(Math.max(1, props.stock), c + 1))}
            onChange={(value) => {
              const parsed = Number(value);
              props.setQuantity(Number.isFinite(parsed) ? Math.max(1, Math.min(Math.max(1, props.stock), Math.round(parsed))) : 1);
            }}
            disabled={outOfStock}
            submitting={isSubmitting}
            error={quantityError}
          />
          <Box style={{ minWidth: '220px', flex: '1 1 220px' }}>
            <Button
              variant="primary"
              size="lg"
              fullWidth
              disabled={isSubmitting || outOfStock || !props.productId}
              loading={isSubmitting}
              onClick={submit}
              aria-label="Add to cart"
            >
              Add to Cart
            </Button>
          </Box>
        </Stack>

        {feedback ? (
          <Alert
            variant={feedback.kind === 'success' ? 'success' : 'error'}
            title={feedback.kind === 'success' ? 'Added to Cart' : 'Add to Cart Failed'}
          >
            {feedback.message}
          </Alert>
        ) : null}
      </Stack>
    </Box>
  );
}

