export default function GeneratedComponent(props: Props) {
  const product = props.product ?? {};
  const productId = product.id ?? '';
  const productName = product.name ?? 'Product';
  const price = product.price ?? 0;
  const currency = product.currency ?? 'USD';
  const rating = product.rating ?? 0;
  const reviewCount = product.reviewCount ?? 0;
  const stock = product.stock ?? 0;
  const description = product.description ?? '';

  const specifications = useMemo(() => parseSpecifications(product.specifications), [product.specifications]);
  const reviews = useMemo(() => parseReviews(product.reviews), [product.reviews]);

  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  useEffect(() => {
    setQuantity((current) => Math.max(1, Math.min(Math.max(1, stock), current)));
  }, [stock]);

  const tabs = useMemo(
    () => [
      {
        key: 'description',
        label: 'Description',
        content: <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{description || 'No description provided.'}</Text>,
      },
      {
        key: 'specifications',
        label: 'Specifications',
        content: <SpecTable specifications={specifications} />,
      },
      {
        key: 'reviews',
        label: 'Reviews',
        content: <ReviewList reviews={reviews} />,
      },
    ],
    [description, reviews, specifications]
  );

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={16}>
        <Card shadow="md" padding={0} radius="lg">
          <Box padding={16}>
            <Stack gap={16}>
              <ProductTopSection
                name={productName}
                price={price}
                currency={currency}
                rating={rating}
                reviewCount={reviewCount}
                stock={stock}
                description={description}
              />

              <Tabs items={tabs} activeKey={activeTab} onChange={setActiveTab} variant="line" size="md" fullWidth />

              <AddToCartArea
                productId={productId}
                stock={stock}
                quantity={quantity}
                setQuantity={setQuantity}
                onAddToCart={props.onAddToCart}
              />
            </Stack>
          </Box>
        </Card>
      </Container>
    </>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Box, Button, Card, Divider, Heading, Input, MotionKeyframes, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Initial messages to display on mount */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Called when user sends a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type Message = {
  sender?: string;
  text?: string;
  timestamp?: string;
};

type TypingState = {
  sender?: string;
  active: boolean;
} | null;

type StreamDetail = {
  type?: string;
  payload?: unknown;
};

type StreamMessagePayload = {
  sender?: string;
  text?: string;
  timestamp?: string;
};

type StreamTypingPayload = {
  sender?: string;
  active?: boolean;
};

function formatTimestamp(timestamp?: string): string {
  const raw = timestamp ?? '';
  if (!raw) return '—';
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return '—';
  return date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

function clusterMessages(items: Message[]) {
  const clusters: Array<{ sender: string; messages: Message[] }> = [];
  items.forEach((message) => {
    const sender = message.sender ?? 'Unknown';
    const last = clusters[clusters.length - 1];
    if (last && last.sender === sender) last.messages.push(message);
    else clusters.push({ sender, messages: [message] });
  });
  return clusters;
}

function isMessagePayload(payload: unknown): payload is StreamMessagePayload {
  return !!payload && typeof payload === 'object';
}

function isTypingPayload(payload: unknown): payload is StreamTypingPayload {
  return !!payload && typeof payload === 'object';
}

export default function GeneratedComponent(props: Props) {
  const title = props.title ?? 'Chat';
  const currentUser = props.currentUser ?? 'You';
  const participantCount = props.participantCount ?? 0;
  const initialMessages = props.messages ?? [];
  const sendMessage = props.sendMessage ?? undefined;

  const [composedText, setComposedText] = useState<string>('');
  const [liveMessages, setLiveMessages] = useState<Message[]>(initialMessages);
  const [typingState, setTypingState] = useState<TypingState>(null);

  const bottomSentinelRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setLiveMessages(initialMessages);
  }, [initialMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<StreamDetail>;
      const detail = customEvent.detail;
      const type = detail?.type;
      const payload = detail?.payload;

      if (type === 'message' && isMessagePayload(payload)) {
        const incoming: Message = {
          sender: payload.sender ?? 'Unknown',
          text: payload.text ?? '',
          timestamp: payload.timestamp ?? '',
        };
        setLiveMessages((prev) => [...prev, incoming]);
      }

      if (type === 'typing' && isTypingPayload(payload)) {
        const incomingSender = payload.sender ?? '';
        const active = Boolean(payload.active);
        if (active && incomingSender !== currentUser) setTypingState({ sender: incomingSender || 'Someone', active: true });
        else setTypingState(null);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, [currentUser]);

  useEffect(() => {
    bottomSentinelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [liveMessages, typingState]);

  const clusters = useMemo(() => clusterMessages(liveMessages), [liveMessages]);

  const typingLabel = useMemo(() => {
    if (!typingState?.active) return '';
    const sender = typingState.sender ?? 'Someone';
    return sender === currentUser ? '' : `${sender} is typing...`;
  }, [currentUser, typingState]);

  const handleSend = () => {
    const text = composedText.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage?.({ text, timestamp });
    setLiveMessages((prev) => [...prev, { sender: currentUser, text, timestamp }]);
    setComposedText('');
  };

  const handleFormSubmit = (event: React.FormEvent) => {
    event.preventDefault();
    handleSend();
  };

  return (
    <>
      <MotionKeyframes />
      <Card shadow="sm" border radius="lg" padding={0}>
        <Stack
          gap="var(--ggui-spacing-4, 16px)"
          style={{
            height: 'min(80vh, calc(var(--ggui-spacing-12, 48px) * 14))',
            minHeight: '560px',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box
            paddingX="var(--ggui-spacing-4, 16px)"
            paddingY="var(--ggui-spacing-4, 16px)"
            style={{ background: 'var(--ggui-color-primary-50, #f0f9ff)' }}
          >
            <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-2, 8px)">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  {title}
                </Heading>
                {typingLabel ? (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite" is="div">
                    {typingLabel}
                  </Text>
                ) : null}
              </Stack>
              <Badge variant="primary" size="sm">
                {participantCount} participant{participantCount === 1 ? '' : 's'}
              </Badge>
            </Stack>
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box
            role="log"
            aria-live="polite"
            aria-relevant="additions text"
            style={{
              flex: 1,
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Stack gap="var(--ggui-spacing-4, 16px)">
              {clusters.map((cluster, clusterIndex) => {
                const isCurrentUser = cluster.sender === currentUser;
                return (
                  <Stack
                    key={`${cluster.sender}-${clusterIndex}`}
                    gap="var(--ggui-spacing-2, 8px)"
                    align={isCurrentUser ? 'end' : 'start'}
                  >
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      align={isCurrentUser ? 'right' : 'left'}
                      is="div"
                    >
                      {cluster.sender}
                    </Text>

                    <Stack gap="var(--ggui-spacing-2, 8px)" align={isCurrentUser ? 'end' : 'start'}>
                      {cluster.messages.map((message, messageIndex) => (
                        <Box
                          key={`${cluster.sender}-${clusterIndex}-${messageIndex}-${message.timestamp ?? 'na'}`}
                          paddingX="var(--ggui-spacing-4, 16px)"
                          paddingY="var(--ggui-spacing-2, 8px)"
                          borderRadius="var(--ggui-shape-radius-lg, 12px)"
                          style={{
                            maxWidth: 'min(78%, 640px)',
                            background: isCurrentUser
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            color: isCurrentUser
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurface, #18181b)',
                            transition: 'transform 200ms ease-in-out, box-shadow 200ms ease-in-out, background-color 200ms ease-in-out',
                            boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-1, 4px)">
                            <Text
                              variant="bodySmall"
                              color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                              is="div"
                            >
                              {message.text ?? ''}
                            </Text>
                            <Text
                              variant="caption"
                              color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                              is="div"
                            >
                              {formatTimestamp(message.timestamp)}
                            </Text>
                          </Stack>
                        </Box>
                      ))}
                    </Stack>
                  </Stack>
                );
              })}

              {typingLabel ? (
                <Box
                  paddingX="var(--ggui-spacing-4, 16px)"
                  paddingY="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{
                    alignSelf: 'flex-start',
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite">
                    {typingLabel}
                  </Text>
                </Box>
              ) : null}

              <div ref={bottomSentinelRef} />
            </Stack>
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box
            paddingX="var(--ggui-spacing-4, 16px)"
            paddingY="var(--ggui-spacing-4, 16px)"
            style={{ background: 'var(--ggui-color-surface, #fafafa)' }}
          >
            <form onSubmit={handleFormSubmit}>
              <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)">
                <Box style={{ flex: 1 }}>
                  <Input
                    label="Message"
                    value={composedText}
                    onChange={setComposedText}
                    placeholder="Type a message..."
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button
                  variant="primary"
                  size="md"
                  aria-label="Send message"
                  disabled={composedText.trim().length === 0}
                  onClick={handleSend}
                >
                  Send
                </Button>
              </Stack>
            </form>
          </Box>
        </Stack>
      </Card>
    </>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Card, Container, Heading, MotionKeyframes, Spinner, Stack, Text, useMotion } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

type Stock = { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number };
type ConnectionState = 'connecting' | 'connected' | 'disconnected';
type MarketStatus = 'open' | 'closed' | 'pre-market' | 'after-hours' | undefined;

type StreamPayload = {
  type?: string;
  eventType?: string;
  event?: unknown;
  symbol?: unknown;
  price?: unknown;
  change?: unknown;
  changePercent?: unknown;
  status?: unknown;
  timestamp?: unknown;
};

const FLASH_DURATION_MS = 850;
const CONNECTIVITY_TIMEOUT_MS = 5000;

function normalizeSymbol(value?: string) {
  return (value ?? '').trim().toUpperCase();
}

function formatNumber(value: number) {
  return value.toFixed(2);
}

function formatSignedNumber(value: number) {
  return `${value > 0 ? '+' : ''}${formatNumber(value)}`;
}

function formatTimestamp(date: Date) {
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

function statusToBadgeVariant(status?: MarketStatus): 'success' | 'warning' | 'default' {
  if (status === 'open') return 'success';
  if (status === 'pre-market' || status === 'after-hours') return 'warning';
  return 'default';
}

function parseEventDetail(detail: unknown): StreamPayload | null {
  if (!detail || typeof detail !== 'object') return null;
  return detail as StreamPayload;
}

function getPayloadType(detail: StreamPayload) {
  if (typeof detail.type === 'string') return detail.type;
  if (typeof detail.eventType === 'string') return detail.eventType;
  return '';
}

function getEventPayload(detail: StreamPayload) {
  if (detail.event && typeof detail.event === 'object') return detail as StreamPayload;
  return detail;
}

function isMarketStatus(value: unknown): value is Exclude<MarketStatus, undefined> {
  return value === 'open' || value === 'closed' || value === 'pre-market' || value === 'after-hours';
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();
  const [stocksState, setStocksState] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [marketStatus, setMarketStatus] = useState<MarketStatus>(undefined);
  const [hasReceivedStreamData, setHasReceivedStreamData] = useState(false);
  const [updatedSymbols, setUpdatedSymbols] = useState<Record<string, number>>({});
  const cleanupTimers = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const clearFlash = (symbol: string) => {
      const existing = cleanupTimers.current[symbol];
      if (existing) clearTimeout(existing);
      cleanupTimers.current[symbol] = setTimeout(() => {
        setUpdatedSymbols((current) => {
          const next = { ...current };
          delete next[symbol];
          return next;
        });
        delete cleanupTimers.current[symbol];
      }, FLASH_DURATION_MS);
    };

    const applyPriceUpdate = (payload: StreamPayload) => {
      const symbol = normalizeSymbol(typeof payload.symbol === 'string' ? payload.symbol : undefined);
      if (!symbol) return;

      const price = typeof payload.price === 'number' ? payload.price : undefined;
      const change = typeof payload.change === 'number' ? payload.change : undefined;
      const changePercent = typeof payload.changePercent === 'number' ? payload.changePercent : undefined;

      setStocksState((current) => {
        const index = current.findIndex((item) => normalizeSymbol(item.symbol) === symbol);
        const nextStock: Stock = {
          ...(index >= 0 ? current[index] : { symbol, name: symbol }),
          symbol,
          name: index >= 0 ? current[index]?.name : symbol,
          ...(price !== undefined ? { price } : {}),
          ...(change !== undefined ? { change } : {}),
          ...(changePercent !== undefined ? { changePercent } : {}),
        };

        if (index >= 0) {
          const next = [...current];
          next[index] = nextStock;
          return next;
        }

        return [...current, nextStock];
      });

      setUpdatedSymbols((current) => ({ ...current, [symbol]: Date.now() }));
      setLastUpdated(new Date());
      setConnectionState('connected');
      setHasReceivedStreamData(true);
      clearFlash(symbol);
    };

    const applyMarketStatus = (payload: StreamPayload) => {
      if (!isMarketStatus(payload.status)) return;
      setMarketStatus(payload.status);
      const timestamp = typeof payload.timestamp === 'string' ? new Date(payload.timestamp) : new Date();
      if (!Number.isNaN(timestamp.getTime())) setLastUpdated(timestamp);
      setConnectionState('connected');
      setHasReceivedStreamData(true);
    };

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const detail = parseEventDetail(customEvent.detail);
      if (!detail) return;
      const payload = getEventPayload(detail);
      const type = getPayloadType(payload);
      if (type === 'priceUpdate') {
        applyPriceUpdate(payload);
        return;
      }
      if (type === 'marketStatus') {
        applyMarketStatus(payload);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);

    const connectivityTimer = setTimeout(() => {
      setConnectionState((current) => (current === 'connecting' ? 'disconnected' : current));
    }, CONNECTIVITY_TIMEOUT_MS);

    const clockTimer = setInterval(() => {
      setLastUpdated((current) => new Date(current.getTime()));
    }, 1000);

    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
      clearTimeout(connectivityTimer);
      clearInterval(clockTimer);
      Object.values(cleanupTimers.current).forEach((timer) => clearTimeout(timer));
      cleanupTimers.current = {};
    };
  }, []);

  const sortedStocks = useMemo(() => [...stocksState], [stocksState]);
  const lastUpdatedText = useMemo(() => formatTimestamp(lastUpdated), [lastUpdated]);

  const connectionLabel =
    connectionState === 'connecting' ? 'Connecting' : connectionState === 'connected' ? 'Live' : 'Disconnected';

  const connectionVariant =
    connectionState === 'connected' ? 'success' : connectionState === 'connecting' ? 'warning' : 'default';

  const streamMessage =
    connectionState === 'connecting'
      ? 'Connecting to live agent updates...'
      : connectionState === 'connected'
        ? hasReceivedStreamData
          ? `Live updates received. ${marketStatus ? `market ${marketStatus}.` : 'market status unavailable.'}`
          : 'Connected and waiting for the first market event...'
        : 'Live feed unavailable. Displaying latest known prices.';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <div
        aria-label="Market Watch dashboard"
        style={{
          minHeight: '100%',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="lg" border>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" justify="between" align="center" wrap>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={2}>Market Watch</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Real-time stock ticker dashboard
                </Text>
              </Stack>

              <Stack align="end" gap="var(--ggui-spacing-1, 4px)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated
                </Text>
                <Text variant="bodySmall" is="div" color="var(--ggui-color-onSurface, #18181b)" aria-live="polite">
                  {lastUpdatedText}
                </Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                  {connectionState === 'connecting' && <Spinner size={16} />}
                  <Badge variant={connectionVariant} size="sm">
                    {connectionLabel}
                  </Badge>
                  <Badge variant={statusToBadgeVariant(marketStatus)} size="sm">
                    {marketStatus ?? 'status unknown'}
                  </Badge>
                </Stack>
              </Stack>
            </Stack>
          </Card>

          <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="lg" border>
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Stream
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite">
                {streamMessage}
              </Text>
            </Stack>
          </Card>

          <div
            aria-label="Stock price grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(min(100%, 280px), 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {sortedStocks.map((stock, index) => {
              const symbol = stock.symbol ?? '—';
              const name = stock.name ?? 'Unknown Company';
              const price = stock.price ?? 0;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const positive = change >= 0;
              const flashActive = !!updatedSymbols[normalizeSymbol(stock.symbol)];
              const label = `${symbol}, ${name}, price ${formatNumber(price)}, change ${formatSignedNumber(
                change
              )}, change percent ${formatSignedNumber(changePercent)}%, ${positive ? 'up' : 'down'}`;

              return (
                <Card
                  key={`${normalizeSymbol(symbol) || 'stock'}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  radius="lg"
                  border
                  role="article"
                  aria-label={label}
                  style={{
                    borderColor: flashActive
                      ? positive
                        ? 'var(--ggui-color-success-200, #bbf7d0)'
                        : 'var(--ggui-color-error-200, #fecaca)'
                      : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    backgroundColor: flashActive
                      ? positive
                        ? 'var(--ggui-color-success-50, #f0fdf4)'
                        : 'var(--ggui-color-error-50, #fef2f2)'
                      : 'var(--ggui-color-surface, #fafafa)',
                    boxShadow: flashActive ? 'var(--ggui-shape-shadow-md)' : undefined,
                    transition: motionEnabled
                      ? 'background-color 200ms ease, border-color 200ms ease, box-shadow 200ms ease, transform 200ms ease'
                      : 'none',
                    transform: flashActive ? 'translateY(-1px)' : 'translateY(0)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)" is="div">
                        {symbol}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                        {name}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)" is="div">
                        ${formatNumber(price)}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Current price
                      </Text>
                    </Stack>

                    <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" wrap>
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color={positive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)'}
                        is="span"
                      >
                        {formatSignedNumber(change)}
                      </Text>
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color={positive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)'}
                        is="span"
                      >
                        <span aria-hidden="true">{positive ? '▲' : '▼'}</span>
                        <span style={{ marginLeft: 'var(--ggui-spacing-1, 4px)' }}>
                          {formatSignedNumber(changePercent)}%
                        </span>
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" is="span">
                        {positive ? 'up' : 'down'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        </Stack>
      </div>
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Badge, Box, Button, Card, Container, Divider, Heading, Input, MotionKeyframes, Progress, Select, Stack, Text, Toggle } from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }) => void;
}

type ProfileData = {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
};

export default function GeneratedComponent(props: Props) {
  const avatarFallback = props.avatarOptions[0] ?? '';
  const roleFallback = props.roleOptions[0] ?? '';
  const initial = props.initialProfile ?? {};

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>(initial.name ?? '');
  const [email, setEmail] = useState<string>(initial.email ?? '');
  const [avatar, setAvatar] = useState<string>(initial.avatar ?? avatarFallback);
  const [role, setRole] = useState<string>(initial.role ?? roleFallback);
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initial.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initial.theme ?? 'light');
  const [nameTouched, setNameTouched] = useState<boolean>(false);
  const [emailTouched, setEmailTouched] = useState<boolean>(false);
  const [roleTouched, setRoleTouched] = useState<boolean>(false);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  useEffect(() => {
    const nextInitial = props.initialProfile ?? {};
    setName(nextInitial.name ?? '');
    setEmail(nextInitial.email ?? '');
    setAvatar(nextInitial.avatar ?? (props.avatarOptions[0] ?? ''));
    setRole(nextInitial.role ?? (props.roleOptions[0] ?? ''));
    setEmailNotifications(nextInitial.emailNotifications ?? true);
    setTheme(nextInitial.theme ?? 'light');
    setCurrentStep(1);
    setNameTouched(false);
    setEmailTouched(false);
    setRoleTouched(false);
    setIsSubmitting(false);
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const trimmedRole = role.trim();

  const nameError = nameTouched && !trimmedName ? 'Name is required.' : '';
  const emailError =
    emailTouched && !trimmedEmail
      ? 'Email is required.'
      : emailTouched && trimmedEmail && !emailRegex.test(trimmedEmail)
      ? 'Enter a valid email address.'
      : '';
  const avatarError = !avatar ? 'Choose an avatar.' : '';
  const roleError = roleTouched && !trimmedRole ? 'Select a role.' : '';

  const isStep1Valid = Boolean(trimmedName) && Boolean(trimmedEmail) && emailRegex.test(trimmedEmail) && Boolean(avatar);
  const isStep2Valid = Boolean(trimmedRole);
  const progressValue = (currentStep / 3) * 100;

  const profilePayload: ProfileData = {
    name: trimmedName,
    email: trimmedEmail,
    avatar,
    role: trimmedRole,
    emailNotifications,
    theme,
  };

  const goNext = () => {
    if (currentStep === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!isStep1Valid) return;
      setCurrentStep(2);
      return;
    }

    if (currentStep === 2) {
      setRoleTouched(true);
      if (!isStep2Valid) return;
      setCurrentStep(3);
    }
  };

  const goBack = () => setCurrentStep((step) => Math.max(1, step - 1));

  const handleComplete = () => {
    if (!isStep1Valid || !isStep2Valid || isSubmitting) return;
    setIsSubmitting(true);
    props.onComplete?.(profilePayload);
    setTimeout(() => setIsSubmitting(false), 0);
  };

  const stepLabel = currentStep === 1 ? 'Profile Setup' : currentStep === 2 ? 'Preferences' : 'Review & Confirm';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack gap="var(--ggui-spacing-3, 12px)">
              <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-3, 12px)" wrap>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={2}>Onboarding Wizard</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Complete your profile in three quick steps.
                  </Text>
                </Stack>
                <Badge variant="primary" size="md">
                  Step {currentStep} / 3
                </Badge>
              </Stack>

              <Progress value={progressValue} max={100} size="sm" showLabel />

              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                {['Profile', 'Prefs', 'Review'].map((label, index) => {
                  const stepNumber = index + 1;
                  const active = currentStep === stepNumber;
                  const done = currentStep > stepNumber;

                  return (
                    <Box
                      key={label}
                      paddingX="var(--ggui-spacing-3, 12px)"
                      paddingY="var(--ggui-spacing-2, 8px)"
                      borderRadius="var(--ggui-shape-radius-full, 9999px)"
                      background={
                        active
                          ? 'var(--ggui-color-primary-100, #e0f2fe)'
                          : done
                          ? 'var(--ggui-color-success-100, #dcfce7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                    >
                      <Text
                        variant="caption"
                        weight="medium"
                        color={
                          active
                            ? 'var(--ggui-color-primary-700, #0369a1)'
                            : done
                            ? 'var(--ggui-color-success-700, #15803d)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                        is="span"
                        aria-current={active ? 'step' : undefined}
                      >
                        {stepNumber}. {label}
                      </Text>
                    </Box>
                  );
                })}
              </Stack>
            </Stack>
          </Box>

          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
            <Box
              style={{
                transition: 'opacity 200ms ease, transform 200ms ease',
                animation: 'ggui-fadeIn 200ms ease-out',
              }}
            >
              {currentStep === 1 && (
                <Stack gap="var(--ggui-spacing-5, 20px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={3}>Profile Setup</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Tell us who you are and pick an emoji avatar.
                    </Text>
                  </Stack>

                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Input
                      label="Name"
                      value={name}
                      onChange={(value) => {
                        setName(value);
                        if (!nameTouched) setNameTouched(true);
                      }}
                      placeholder="Jane Doe"
                      required
                      error={nameError}
                    />
                    <Input
                      label="Email"
                      type="email"
                      value={email}
                      onChange={(value) => {
                        setEmail(value);
                        if (!emailTouched) setEmailTouched(true);
                      }}
                      placeholder="jane@example.com"
                      required
                      error={emailError}
                    />
                  </Stack>

                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text variant="label" is="label">
                      Avatar Selection
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Choose one of the emoji avatars below.
                    </Text>
                    {avatarError ? (
                      <Text variant="caption" color="var(--ggui-color-error, #dc2626)">
                        {avatarError}
                      </Text>
                    ) : null}
                    <Box
                      role="radiogroup"
                      aria-label="Avatar selection"
                      style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-3, 12px)' }}
                    >
                      {props.avatarOptions.map((option) => {
                        const selected = avatar === option;
                        return (
                          <Button
                            key={option}
                            variant={selected ? 'primary' : 'secondary'}
                            size="lg"
                            aria-label={`Select avatar ${option}`}
                            aria-pressed={selected}
                            onClick={() => setAvatar(option)}
                            style={{
                              minWidth: 'var(--ggui-spacing-12, 48px)',
                              transition: 'all 200ms ease',
                              transform: selected ? 'translateY(-1px)' : 'translateY(0)',
                            }}
                          >
                            <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', lineHeight: 1 }}>{option}</span>
                          </Button>
                        );
                      })}
                    </Box>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap="var(--ggui-spacing-5, 20px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={3}>Preferences</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Customize your workspace and notification settings.
                    </Text>
                  </Stack>

                  <Select
                    label="Role"
                    value={role}
                    onChange={(value) => {
                      setRole(value);
                      if (!roleTouched) setRoleTouched(true);
                    }}
                    options={props.roleOptions.map((option) => ({ value: option, label: option }))}
                    placeholder="Select a role"
                    required
                    error={roleError}
                  />

                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Box
                      padding="var(--ggui-spacing-4, 16px)"
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Text variant="label">Notifications</Text>
                        <Toggle
                          label="Email notifications"
                          checked={emailNotifications}
                          onChange={setEmailNotifications}
                          size="md"
                        />
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Turn alerts on or off for product updates and reminders.
                        </Text>
                      </Stack>
                    </Box>

                    <Box
                      padding="var(--ggui-spacing-4, 16px)"
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Text variant="label">Theme preference</Text>
                        <Toggle
                          label={`Dark mode ${theme === 'dark' ? 'enabled' : 'disabled'}`}
                          checked={theme === 'dark'}
                          onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                          size="md"
                        />
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Switch between light and dark appearance.
                        </Text>
                      </Stack>
                    </Box>
                  </Stack>
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap="var(--ggui-spacing-5, 20px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={3}>Review & Confirm</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Review your selections before completing setup.
                    </Text>
                  </Stack>

                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  >
                    <Stack gap="var(--ggui-spacing-3, 12px)">
                      <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-3, 12px)">
                        <Text variant="label">Profile</Text>
                        <Badge variant="primary" size="sm">
                          Ready
                        </Badge>
                      </Stack>
                      <Divider margin="var(--ggui-spacing-2, 8px)" />
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <SummaryRow label="Name" value={profilePayload.name || '—'} />
                        <SummaryRow label="Email" value={profilePayload.email || '—'} />
                        <SummaryRow label="Avatar" value={profilePayload.avatar || '—'} />
                        <SummaryRow label="Role" value={profilePayload.role || '—'} />
                        <SummaryRow label="Notifications" value={profilePayload.emailNotifications ? 'On' : 'Off'} />
                        <SummaryRow label="Theme" value={profilePayload.theme} />
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              )}
            </Box>
          </Card>

          <Box aria-live="polite">
            <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" justify="between" align="center" wrap>
              <Button variant="ghost" onClick={goBack} disabled={currentStep === 1 || isSubmitting} aria-label="Go back">
                Go Back
              </Button>

              <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="center" wrap>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {currentStep === 1
                    ? isStep1Valid
                      ? 'Profile is ready to continue.'
                      : 'Complete required fields to continue.'
                    : currentStep === 2
                    ? isStep2Valid
                      ? 'Preferences are ready to review.'
                      : 'Select a role to continue.'
                    : 'Ready to complete setup.'}
                </Text>

                {currentStep < 3 ? (
                  <Button
                    variant="primary"
                    onClick={goNext}
                    aria-label="Next step"
                    disabled={currentStep === 1 ? !isStep1Valid || isSubmitting : !isStep2Valid || isSubmitting}
                  >
                    Next
                  </Button>
                ) : (
                  <Button
                    variant="primary"
                    onClick={handleComplete}
                    aria-label="Complete setup"
                    loading={isSubmitting}
                    disabled={isSubmitting}
                  >
                    Complete Setup
                  </Button>
                )}
              </Stack>
            </Stack>
          </Box>
        </Stack>
      </Container>
    </>
  );
}

function SummaryRow({ label, value }: { label: string; value: string }) {
  return (
    <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-3, 12px)">
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {label}
      </Text>
      <Text variant="bodySmall" weight="medium" align="right">
        {value}
      </Text>
    </Stack>
  );
}
